from agent import *from models.products import *def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.browser.use_new_parser = True    session.queue(Request('http://press-start.com.au/category/reviews/'), process_catlist, {})def process_catlist(data, context, session):    strip_namespace(data)    cats = data.xpath('//ul[@class="options"]/li/a[@class="block-subcat"]')    for cat in cats:        url = cat.xpath("@href").string()        name = cat.xpath("text()").string()        if url and name:            name = name.replace(' Reviews', '')            if not name in ['Movie', 'Tech']:                name = "Games|" + name            session.queue(Request(url), process_category, dict(context, cat=name))def process_category(data, context, session):    strip_namespace(data)    revs = data.xpath("//div[@data-id=0]//h3[@class='title']/a")    for rev in revs:        url = rev.xpath("@href").string()        title = rev.xpath("./text()").string()        if url and title:            session.queue(Request(url), process_review, dict(context, url=url, title=title))    next_url = data.xpath('//head/link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_category, dict(context))def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['title'].split(' Review')[0]    product.category = context['cat']    product.url = context['url']    product.ssid = context['url'].split('/')[-2]    review = Review()    review.type = 'pro'    review.title = data.xpath('//head/title/text()').string() or context['title']    review.url = product.url    review.ssid = product.ssid    date = data.xpath('//meta[@property="article:published_time"]/@content').string()    if date:        review.date = date.split('T')[0]    author_name = data.xpath('//span[@class="byline-part author"]/a/span[@class="byline-by-name"]/text()').string()    author_url = data.xpath('//span[@class="byline-part author"]/a/@href').string()    if author_name:        if author_url:            review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_url.split('/')[-2]))        else:            review.authors.append(Person(name=author_name, ssid=author_name))    grade_overall = data.xpath('//div[@class="score__wrap lr-all-c"]/div[@class="score"]/text()').string()    if grade_overall:        review.grades.append(Grade(type='overall', value=float(grade_overall), best=10.0))    pros = data.xpath("//div[@class='cb-pros-cons cb-pro']")    for pro in pros:        line = pro.xpath(".//text()").string(multiple=True)        if line:            review.properties.append(ReviewProperty(type='pros', value=line))    if not pros:        pros = data.xpath("//p[contains(., 'Pros')]/following-sibling::ul[1]/li//text()")        if not pros:            pros = data.xpath("//div[@class='lets-review-block__procon lets-review-block__pro']//text()")        for pro in pros:            line = pro.string(multiple=True)            if line:                review.properties.append(ReviewProperty(type='pros', value=line))    cons = data.xpath("//div[@class='cb-pros-cons cb-con']")    for con in cons:        line = con.xpath(".//text()").string(multiple=True)        if line:            review.properties.append(ReviewProperty(type='cons', value=line))    if not cons:        cons = data.xpath("//p[contains(., 'Cons')]/following-sibling::ul[1]/li//text()")        if not cons:            cons = data.xpath("//div[@class='lets-review-block__procon lets-review-block__con']//text()")        for con in cons:            line = con.string(multiple=True)            if line:                review.properties.append(ReviewProperty(type='cons', value=line))    excerpt = data.xpath("//div[regexp:test(@class,'entry-content ')]/p[following-sibling::node()[regexp:test(normalize-space(.),'Conclusion','i')]]//text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("//div[regexp:test(@class,'entry-content ')]/p[following-sibling::div[@data-pid]]//text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("//div[regexp:test(@class,'entry-content ')]/p//text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("(//article/div[@class='entry-content-wrap clearfix']//img/@src[contains(., 'CONCLUSION')])[1]/parent::img/parent::p//text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("(//article//div/div/p[last()])[1]//text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("//div[regexp:test(@class,'single-content')]//section[@class='cb-entry-content clearfix']//p//text()").string(multiple=True)    if not excerpt:        excerpt = data.xpath("//article[contains(@class, 'entry-content clearfix')]//p//text()").string(multiple=True)    conclusion = data.xpath("//img[contains(@src, 'CONCLUSION') or contains(@src, 'Conclusion') or contains(@src, 'conclusion')]//parent::p//following-sibling::p//text()").string(multiple=True)    if not(conclusion):        conclusion = data.xpath("//img[contains(@src, 'CONCLUSION') or contains(@src, 'Conclusion') or contains(@src, 'conclusion')]//following-sibling::text()").string(multiple=True)    if not(conclusion):        conclusion = data.xpath("descendant::div[@itemprop='reviewBody']//text()").string(multiple=True)    if not(conclusion):        conclusion = data.xpath("descendant::div[regexp:test(@class,'entry-content ')]/p[preceding-sibling::node()[regexp:test(normalize-space(.),'Conclusion','i')]]//text()").string(multiple=True)    if not(conclusion):        conclusion = data.xpath("//div[@class='lets-review-block lets-review-block__conclusion__wrap lets-review-block__pad']/div[@class='lets-review-block__conclusion']//text()").string(multiple=True)    if conclusion:        if conclusion in excerpt:            excerpt = excerpt.replace(conclusion, ' ')        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))    summary = data.xpath("//img[contains(@src, 'PRESENTATION') or contains(@src, 'presentation') or contains(@src, 'Presentation')]//following-sibling::text()").string(multiple=True)    if not summary:        summary = data.xpath("//img[contains(@src, 'PRESENTATION') or contains(@src, 'presentation') or contains(@src, 'Presentation')]//parent::p//text()").string(multiple=True)    if not summary:        summary = data.xpath("//img[contains(@src, 'PRESENTATION') or contains(@src, 'presentation') or contains(@src, 'Presentation')]//parent::a//parent::p//text()").string(multiple=True)    if not summary:        summary = data.xpath('//div[@class="meta"]/div/p/text()').string(multiple=True)    if summary:        if summary in excerpt:            excerpt = excerpt.replace(summary, ' ')        review.properties.append(ReviewProperty(type='summary', value=summary))    if excerpt:        excerpt = excerpt.strip()        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))    product.reviews.append(review)    session.emit(product)